"""
Pytest tests for leave request submission requirements:
- Full-time employees can submit leave requests for 1–30 business days.
- Requests spanning more than 30 business days require hr-admin approval.
- The action must be idempotent under retry.
"""

import uuid
from unittest.mock import MagicMock, patch, call
import pytest

# ---------------------------------------------------------------------------
# Domain model stubs – replace with real imports from your application
# ---------------------------------------------------------------------------
from dataclasses import dataclass, field
from enum import Enum, auto
from typing import Optional


class EmployeeType(Enum):
    FULL_TIME = auto()
    PART_TIME = auto()
    CONTRACTOR = auto()


class LeaveStatus(Enum):
    PENDING = "PENDING"
    PENDING_HR_APPROVAL = "PENDING_HR_APPROVAL"
    APPROVED = "APPROVED"
    REJECTED = "REJECTED"


class LeaveRequestError(Exception):
    """Base error for leave request failures."""


class InvalidDurationError(LeaveRequestError):
    """Raised when the requested duration is outside the allowed range."""


class UnauthorisedEmployeeTypeError(LeaveRequestError):
    """Raised when a non-full-time employee tries to submit a leave request."""


@dataclass
class Employee:
    employee_id: str
    employee_type: EmployeeType


@dataclass
class LeaveRequest:
    request_id: str
    employee_id: str
    business_days: int
    status: LeaveStatus = LeaveStatus.PENDING
    requires_hr_approval: bool = False


# ---------------------------------------------------------------------------
# Service under test stub
# ---------------------------------------------------------------------------

class LeaveRequestService:
    """
    Thin wrapper around persistence + approval routing.
    Replace the body with real application logic.
    """

    STANDARD_MAX_DAYS = 30
    STANDARD_MIN_DAYS = 1

    def __init__(self, repository, approval_router):
        self._repo = repository
        self._router = approval_router

    def submit(self, employee: Employee, business_days: int,
               idempotency_key: str) -> LeaveRequest:
        """
        Submit a leave request.

        Parameters
        ----------
        employee        : the requesting employee
        business_days   : length of the requested leave in business days
        idempotency_key : caller-supplied unique key; a second call with the
                          same key returns the original result unchanged.

        Returns
        -------
        LeaveRequest
        """
        # --- idempotency check -------------------------------------------
        existing = self._repo.find_by_idempotency_key(idempotency_key)
        if existing is not None:
            return existing

        # --- authorisation ---------------------------------------------------
        if employee.employee_type != EmployeeType.FULL_TIME:
            raise UnauthorisedEmployeeTypeError(
                f"Only full-time employees may submit leave requests; "
                f"employee {employee.employee_id} is {employee.employee_type.name}."
            )

        # --- duration validation ---------------------------------------------
        if business_days < self.STANDARD_MIN_DAYS:
            raise InvalidDurationError(
                f"Leave duration must be at least {self.STANDARD_MIN_DAYS} "
                f"business day(s); got {business_days}."
            )

        # --- routing ---------------------------------------------------------
        requires_hr = business_days > self.STANDARD_MAX_DAYS
        status = (
            LeaveStatus.PENDING_HR_APPROVAL if requires_hr else LeaveStatus.PENDING
        )

        request = LeaveRequest(
            request_id=str(uuid.uuid4()),
            employee_id=employee.employee_id,
            business_days=business_days,
            status=status,
            requires_hr_approval=requires_hr,
        )

        self._repo.save(request, idempotency_key=idempotency_key)

        if requires_hr:
            self._router.route_to_hr_admin(request)

        return request


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture()
def mock_repository():
    repo = MagicMock()
    # Default: no pre-existing request for any idempotency key
    repo.find_by_idempotency_key.return_value = None
    return repo


@pytest.fixture()
def mock_approval_router():
    return MagicMock()


@pytest.fixture()
def service(mock_repository, mock_approval_router):
    return LeaveRequestService(
        repository=mock_repository,
        approval_router=mock_approval_router,
    )


@pytest.fixture()
def full_time_employee():
    return Employee(employee_id="EMP-001", employee_type=EmployeeType.FULL_TIME)


@pytest.fixture()
def part_time_employee():
    return Employee(employee_id="EMP-002", employee_type=EmployeeType.PART_TIME)


@pytest.fixture()
def contractor_employee():
    return Employee(employee_id="EMP-003", employee_type=EmployeeType.CONTRACTOR)


def _idempotency_key() -> str:
    return str(uuid.uuid4())


# ===========================================================================
# Test class: valid durations (1 – 30 business days)
# ===========================================================================

class TestValidDurationRange:
    """Full-time employees may submit requests for 1–30 business days."""

    @pytest.mark.parametrize("days", [1, 15, 30])
    def test_valid_duration_returns_leave_request(
        self, service, full_time_employee, days
    ):
        result = service.submit(full_time_employee, days, _idempotency_key())

        assert isinstance(result, LeaveRequest)
        assert result.business_days == days
        assert result.employee_id == full_time_employee.employee_id

    @pytest.mark.parametrize("days", [1, 15, 30])
    def test_valid_duration_status_is_pending(
        self, service, full_time_employee, days
    ):
        result = service.submit(full_time_employee, days, _idempotency_key())

        assert result.status == LeaveStatus.PENDING

    @pytest.mark.parametrize("days", [1, 15, 30])
    def test_valid_duration_does_not_require_hr_approval(
        self, service, full_time_employee, days
    ):
        result = service.submit(full_time_employee, days, _idempotency_key())

        assert result.requires_hr_approval is False

    @pytest.mark.parametrize("days", [1, 15, 30])
    def test_valid_duration_persists_request(
        self, service, mock_repository, full_time_employee, days
    ):
        key = _idempotency_key()
        result = service.submit(full_time_employee, days, key)

        mock_repository.save.assert_called_once_with(result, idempotency_key=key)

    @pytest.mark.parametrize("days", [1, 15, 30])
    def test_valid_duration_does_not_route_to_hr(
        self, service, mock_approval_router, full_time_employee, days
    ):
        service.submit(full_time_employee, days, _idempotency_key())

        mock_approval_router.route_to_hr_admin.assert_not_called()

    def test_boundary_minimum_one_day(self, service, full_time_employee):
        result = service.submit(full_time_employee, 1, _idempotency_key())

        assert result.business_days == 1

    def test_boundary_maximum_thirty_days(self, service, full_time_employee):
        result = service.submit(full_time_employee, 30, _idempotency_key())

        assert result.business_days == 30


