class TestHrAdminApprovalRequired:
    """Requests for more than 30 business days must be routed to hr-admin."""

    @pytest.mark.parametrize("days", [31, 45, 365])
    def test_over_threshold_status_is_pending_hr_approval(
        self, service, full_time_employee, days
    ):
        result = service.submit(full_time_employee, days, _idempotency_key())

        assert result.status == LeaveStatus.PENDING_HR_APPROVAL

    @pytest.mark.parametrize("days", [31, 45, 365])
    def test_over_threshold_requires_hr_approval_flag(
        self, service, full_time_employee, days
    ):
        result = service.submit(full_time_employee, days, _idempotency_key())

        assert result.requires_hr_approval is True

    @pytest.mark.parametrize("days", [31, 45, 365])
    def test_over_threshold_routes_to_hr_admin(
        self, service, mock_approval_router, full_time_employee, days
    ):
        result = service.submit(full_time_employee, days, _idempotency_key())

        mock_approval_router.route_to_hr_admin.assert_called_once_with(result)

    @pytest.mark.parametrize("days", [31, 45, 365])
    def test_over_threshold_persists_request(
        self, service, mock_repository, full_time_employee, days
    ):
        key = _idempotency_key()
        result = service.submit(full_time_employee, days, key)

        mock_repository.save.assert_called_once_with(result, idempotency_key=key)

    def test_boundary_thirty_one_days_triggers_hr_approval(
        self, service, full_time_employee
    ):
        result = service.submit(full_time_employee, 31, _idempotency_key())

        assert result.requires_hr_approval is True
        assert result.status == LeaveStatus.PENDING_HR_APPROVAL

