class TestEmployeeTypeAuthorisation:
    """Only full-time employees are permitted to submit leave requests."""

    def test_full_time_employee_is_permitted(self, service, full_time_employee):
        # Should not raise
        result = service.submit(full_time_employee, 5, _idempotency_key())
