# ===========================================================================
# Test class: idempotency under retry
# ===========================================================================

class TestIdempotency:
    """Submitting the same idempotency key twice must return the original result."""

    def test_retry_returns_original_request(
        self, service, mock_repository, full_time_employee
    ):
        key = _idempotency_key()
        original = LeaveRequest(
            request_id="fixed-id-123",
            employee_id=full_time_employee.employee_id,
            business_days=5,
            status=LeaveStatus.PENDING,
        )
        # First call: no existing record; second call: return the original
        mock_repository.find_by_idempotency_key.side_effect = [None, original]

        first_result = service.submit(full_time_employee, 5, key)
        second_result = service.submit(full_time_employee, 5, key)

        assert second_result.request_id == first_result.request_id

    def test_retry_does_not_persist_again(
        self, service, mock_repository, full_time_employee
    ):
        key = _idempotency_key()
        original = LeaveRequest(
            request_id="fixed-id-456",
            employee_id=full_time_employee.employee_id,
            business_days=5,
            status=LeaveStatus.PENDING,
        )
        mock_repository.find_by_idempotency_key.side_effect = [None, original]

        service.submit(full_time_employee, 5, key)
        service.submit(full_time_employee, 5, key)

        # save() must have been called exactly once (on the first submission)
        assert mock_repository.save.call_count == 1

    def test_retry_does_not_route_to_hr_again(
        self, service, mock_repository, mock_approval_router, full_time_employee
    ):
        key = _idempotency_key()
        original = LeaveRequest(
            request_id="fixed-id-789",
            employee_id=full_time_employee.employee_id,
            business_days=35,
            status=LeaveStatus.PENDING_HR_APPROVAL,
            requires_hr_approval=True,
        )
        mock_repository.find_by_idempotency_key.side_effect = [None, original]

        service.submit(full_time_employee, 35, key)
        service.submit(full_time_employee, 35, key)

        # HR routing must happen exactly once
        assert mock_approval_router.route_to_hr_admin.call_count == 1

    def test_different_idempotency_keys_create_separate_requests(
        self, service, mock_repository, full_time_employee
    ):
        mock_repository.find_by_idempotency_key.return_value = None

        result_a = service.submit(full_time_employee, 5, _idempotency_key())
        result_b = service.submit(full_time_employee, 5, _idempotency_key())

        assert result_a.request_id != result_b.request_id
        assert mock_repository.save.call_count == 2

    def test_idempotency_key_is_passed_to_repository_lookup(
        self, service, mock_repository, full_time_employee
    ):
        key = _idempotency_key()
        service.submit(full_time_employee, 5, key)

        mock_repository.find_by_idempotency_key.assert_called_with(key)

    @pytest.mark.parametrize("retry_count", [2, 3, 10])
    def test_many_retries_still_idempotent(
        self, service, mock_repository, full_time_employee, retry_count
    ):
        key = _idempotency_key()
        original = LeaveRequest(
            request_id="stable-id",
            employee_id=full_time_employee.employee_id,
            business_days=10,
            status=LeaveStatus.PENDING,
        )
        # First call hits no existing record; all subsequent calls return original
        mock_repository.find_by_idempotency_key.side_effect = (
            [None] + [original] * retry_count
        )

        results = [
            service.submit(full_time_employee, 10, key)
            for _ in range(retry_count + 1)
        ]

        request_ids = {r.request_id for r in results}
        assert len(request_ids) == 1, (
            "All retries must return the same request_id"
        )
        assert mock_repository.save.call_count == 1

    def test_idempotency_check_happens_before_validation(
        self, service, mock_repository, full_time_employee
    ):
        """
        If the idempotency key already exists in the store the service must
        return the cached result without re-running business-rule validation.
        This guards against edge cases where the stored duration might differ
        from the retried payload.
        """
        key = _idempotency_key()
        original = LeaveRequest(
            request_id="cached-id",
            employee_id=full_time_employee.employee_id,
            business_days=5,
            status=LeaveStatus.PENDING,
        )
        mock_repository.find_by_idempotency_key.return_value = original

        # Even if caller mistakenly retries with 0 days, the cached result
        # is returned rather than an InvalidDurationError being raised.
        result = service.submit(full_time_employee, 0, key)

        assert result.request_id == "cached-id"
        mock_repository.save.assert_not_called()
